//! Request-scoped identity shared by the MindLeak and Lodestar MCP planes.

use std::collections::HashSet;
use std::sync::{Arc, RwLock};

use sha2::{Digest, Sha256};

const TOKEN_HEX_LEN: usize = 32;
const AGENT_DIGEST_BYTES: usize = 16;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SessionIdentity {
    pub agent_id: String,
}

#[derive(Clone)]
pub struct SessionRegistry {
    base: Arc<str>,
    registered: Arc<RwLock<HashSet<[u8; 32]>>>,
}

impl SessionRegistry {
    pub fn new(base: &str) -> Result<Self, String> {
        let base = base.trim();
        if base.is_empty()
            || !base
                .chars()
                .all(|character| character.is_ascii_alphanumeric() || "._-".contains(character))
        {
            return Err(
                "session agent base must contain only ASCII letters, digits, '.', '_', or '-'"
                    .to_string(),
            );
        }
        Ok(Self {
            base: Arc::from(base),
            registered: Arc::new(RwLock::new(HashSet::new())),
        })
    }

    pub fn open_session(&self, token: &str) -> Result<SessionIdentity, String> {
        let digest = token_digest(token)?;
        self.registered
            .write()
            .map_err(|_| "session registry lock poisoned".to_string())?
            .insert(digest);
        Ok(self.identity_for(digest))
    }

    pub fn resolve(&self, token: &str) -> Result<SessionIdentity, String> {
        let digest = token_digest(token)?;
        let registered = self
            .registered
            .read()
            .map_err(|_| "session registry lock poisoned".to_string())?;
        if !registered.contains(&digest) {
            return Err("unknown session_id; call open_session first".to_string());
        }
        Ok(self.identity_for(digest))
    }

    fn identity_for(&self, digest: [u8; 32]) -> SessionIdentity {
        let fingerprint = digest[..AGENT_DIGEST_BYTES]
            .iter()
            .map(|byte| format!("{byte:02x}"))
            .collect::<String>();
        SessionIdentity {
            agent_id: format!("session:v1:{}:{fingerprint}", self.base),
        }
    }
}

fn token_digest(token: &str) -> Result<[u8; 32], String> {
    if token.len() != TOKEN_HEX_LEN
        || !token
            .chars()
            .all(|character| character.is_ascii_hexdigit() && !character.is_ascii_uppercase())
    {
        return Err("session_id must be exactly 32 lowercase hexadecimal characters".to_string());
    }
    Ok(Sha256::digest(token.as_bytes()).into())
}

pub fn compatible_legacy_owner(expected_owner: &str, target_agent: &str) -> bool {
    let Some(rest) = target_agent.strip_prefix("session:v1:") else {
        return false;
    };
    let Some((base, fingerprint)) = rest.rsplit_once(':') else {
        return false;
    };
    if fingerprint.len() != AGENT_DIGEST_BYTES * 2
        || !fingerprint
            .chars()
            .all(|character| character.is_ascii_hexdigit())
    {
        return false;
    }
    if expected_owner == base {
        return true;
    }
    expected_owner
        .strip_prefix(&format!("{base}-"))
        .is_some_and(|nonce| nonce.len() == 8 && nonce.chars().all(|c| c.is_ascii_hexdigit()))
}

#[cfg(test)]
mod tests {
    use super::*;

    const SESSION_A: &str = "00112233445566778899aabbccddeeff";
    const SESSION_B: &str = "ffeeddccbbaa99887766554433221100";

    #[test]
    fn registration_is_required_and_idempotent() {
        let registry = SessionRegistry::new("copilot").unwrap();
        assert!(registry.resolve(SESSION_A).is_err());

        let first = registry.open_session(SESSION_A).unwrap();
        let retry = registry.open_session(SESSION_A).unwrap();
        assert_eq!(retry, first);
        assert_eq!(registry.resolve(SESSION_A).unwrap(), first);
    }

    #[test]
    fn logical_sessions_are_distinct_but_restart_stable() {
        let first_process = SessionRegistry::new("copilot").unwrap();
        let first = first_process.open_session(SESSION_A).unwrap();
        let second = first_process.open_session(SESSION_B).unwrap();
        assert_ne!(first, second);

        let restarted = SessionRegistry::new("copilot").unwrap();
        assert_eq!(restarted.open_session(SESSION_A).unwrap(), first);
    }

    #[test]
    fn malformed_tokens_and_bases_are_rejected() {
        let registry = SessionRegistry::new("copilot").unwrap();
        for token in [
            "short",
            "00112233445566778899AABBCCDDEEFF",
            "00112233445566778899aabbccddeefg",
        ] {
            assert!(registry.open_session(token).is_err());
        }
        assert!(SessionRegistry::new("copilot:unsafe").is_err());
    }

    #[test]
    fn only_compatible_legacy_owners_can_transfer() {
        let agent = SessionRegistry::new("copilot")
            .unwrap()
            .open_session(SESSION_A)
            .unwrap()
            .agent_id;
        assert!(compatible_legacy_owner("copilot", &agent));
        assert!(compatible_legacy_owner("copilot-abcd1234", &agent));
        assert!(!compatible_legacy_owner("claude-abcd1234", &agent));
        assert!(!compatible_legacy_owner("copilot-nothex!!", &agent));
        assert!(!compatible_legacy_owner("copilot-abcd1234", "copilot-new"));
    }
}
